    if ( (*(_BYTE *)(*((_QWORD *)this + 6) + 112LL) & 7) == 0 ) {
        v9  = EvaluateCurrentState(&g_Feature_2160550201_59010878_FeatureDescriptorDetails);
        v11 = *((_DWORD *)this + 66);                 // raw size from log block header
        if ( v9 )                                       // feature state != 1 -> align
            AlignedBufferSize = CClfsRequest::GetAlignedBufferSize(this, v11);
            v15 = ClfsProbeAndAllocateMdl(*(_BYTE*)(v12+64), *(void**)(v12+112), AlignedBufferSize, ...);
        else                                            // feature state == 1 -> raw size
            v15 = ClfsProbeAndAllocateMdl(*(_BYTE*)(*((_QWORD*)this+6)+64), *(void**)(*((_QWORD*)this+6)+112), v11, ...);
    }

Patched CClfsRequest::WriteRestart (0x1C0057594):
    if ( (*(_BYTE *)(*((_QWORD *)this + 6) + 112LL) & 7) == 0 ) {
        v9 = *((_QWORD *)this + 6);
        AlignedBufferSize = CClfsRequest::GetAlignedBufferSize(this, *((_DWORD *)this + 66));
        v2 = ClfsProbeAndAllocateMdl(*(_BYTE*)(v9+64), *(void**)(v9+112), AlignedBufferSize, ...);
        // EvaluateCurrentState call and raw-size branch removed
    }

The MDL buffer pointer (*(void**)(...+112)) is identical in both branches and both builds; only the length differs, and the removed branch used the smaller value.

GetAlignedBufferSize (sub_1C0027860) rounds UP:
    if ( device_query(...) < 0 || sector_size <= 0x200 )
        return (a2 + 0x1ff) & 0xfffffe00;      // >= a2
    else
        return ~(sector_size-1) & (a2 + sector_size-1);  // >= a2

ClfsProbeAndAllocateMdl (sub_1C0010890) describes a pre-existing buffer:
